  /**
   * Link
   *
   * URL or DOI link to the reference
   */
  link?: string | null;
  /**
   * Reference Excerpt
   *
   * Relevant excerpt from the reference that is why we should cite or discuss it
   */
  reference_excerpt: string;
  /**
   * Publication type (e.g., journal, website, book, preprint)
   */
